using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class FetchApiTool
{
    [McpServerTool, Description("Fetches data from an external API endpoint and returns the response body.")]
    public static async Task<string> FetchApi(
        IHttpClientFactory httpClientFactory,
        [Description("The full URL to fetch (e.g. https://api.example.com/data)")] string url,
        CancellationToken cancellationToken)
    {
        using var client = httpClientFactory.CreateClient("ApiClient");
        var response = await client.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a prompt that asks for a concise summary of the provided text.")]
    public static ChatMessage[] Summarize(
        [Description("The text to summarize")] string text,
        [Description("Optional maximum length constraint (e.g. '2 sentences', '100 words')")] string? maxLength = null)
    {
        var constraint = string.IsNullOrWhiteSpace(maxLength)
            ? string.Empty
            : $" Keep the summary within {maxLength}.";

        return
        [
            new(Role.User, $"Please provide a concise summary of the following text.{constraint}\n\n{text}")
        ];
    }
}

